    }

    public static void main(String[] args) {
        StructureSelector ss = new StructureSelector();
        String[] cases = {"undo-stack", "job-queue", "word-count",
                          "ranked-scores", "ordered-list", "unique-emails"};
        for (String uc : cases) {
            ss.explainSelection(uc);
        }
    }
}

import java.util.*;

public class TradeoffAnalyzer {

    // Each entry: {lookupBest, insertBest, deleteBest} as Big-O strings
    private static final Map<String, String[]> complexities = new LinkedHashMap<>();

    static {
        complexities.put("Array",      new String[]{"O(1)", "O(n)", "O(n)"});
        complexities.put("LinkedList", new String[]{"O(n)", "O(1)", "O(1)"});
        // TODO: add HashMap entry: lookup=O(1), insert=O(1), delete=O(1)
        // TODO: add TreeMap entry: lookup=O(log n), insert=O(log n), delete=O(log n)
    }

    public void printTradeoffs() {
        System.out.printf("%-12s %-10s %-10s %-10s%n", "Structure", "Lookup", "Insert", "Delete");
        for (Map.Entry<String, String[]> e : complexities.entrySet()) {
            String[] c = e.getValue();
            System.out.printf("%-12s %-10s %-10s %-10s%n", e.getKey(), c[0], c[1], c[2]);
        }
    }

    public String bestForOperation(String op) {
        // Return structure with O(1) in the given op slot
        // op is "lookup", "insert", or "delete"
        int idx = op.equals("lookup") ? 0 : op.equals("insert") ? 1 : 2;
        for (Map.Entry<String, String[]> e : complexities.entrySet()) {
            if ("O(1)".equals(e.getValue()[idx])) return e.getKey();
        }
        return "None";
    }

    public static void main(String[] args) {
        TradeoffAnalyzer ta = new TradeoffAnalyzer();
        ta.printTradeoffs();
        System.out.println("Best for lookup: " + ta.bestForOperation("lookup"));
        System.out.println("Best for insert: " + ta.bestForOperation("insert"));
    }
}
